        for i, val in enumerate(nums):
            if i > 0 and val == nums[i-1]: continue
            l, r = i + 1, len(nums) - 1
            while l < r:
                s = val + nums[l] + nums[r]
                if s > 0: r -= 1
                elif s < 0: l += 1
