        if (i < 0 || i >= board.size() || j < 0 || j >= board[0].size() || board[i][j] != word[k]) return false;
        char temp = board[i][j];
        board[i][j] = '#';
        bool res = backtrack(board, word, i + 1, j, k + 1) ||
                   backtrack(board, word, i - 1, j, k + 1) ||
                   backtrack(board, word, i, j + 1, k + 1) ||
                   backtrack(board, word, i, j - 1, k + 1);
        board[i][j] = temp;
        return res;
    }
};

