class Solution:
    def solveSudoku(self, board: List[List[str]]) -> None:
        def isValid(r, c, k):
            for i in range(9):
                if board[i][c] == str(k): return False
                if board[r][i] == str(k): return False
                if board[3 * (r // 3) + i // 3][3 * (c // 3) + i % 3] == str(k): return False
            return True
        def solve():
            for i in range(9):
                for j in range(9):
                    if board[i][j] == '.':
                        for k in range(1, 10):
                            if isValid(i, j, k):
                                board[i][j] = str(k)
                                if solve(): return True
                                board[i][j] = '.'
                        return False
            return True
        solve()

