class Solution:
    def partition(self, s: str) -> List[List[str]]:
        res = []
        def isPalindrome(l, r):
            while l < r:
                if s[l] != s[r]:
                    return False
                l, r = l + 1, r - 1
            return True
        def backtrack(i, curr):
            if i >= len(s):
                res.append(curr[:])
                return
            for j in range(i, len(s)):
                if isPalindrome(i, j):
                    curr.append(s[i:j+1])
                    backtrack(j + 1, curr)
                    curr.pop()
        backtrack(0, [])
        return res

