public:
    vector<string> restoreIpAddresses(string s) {
        vector<string> res;
        backtrack(s, 0, "", 0, res);
        return res;
    }
private:
    void backtrack(string s, int i, string curr, int dots, vector<string>& res) {
        if (dots == 4 && i == s.length()) {
            res.push_back(curr.substr(0, curr.length() - 1));
            return;
        }
        if (dots > 4) return;
        for (int j = i; j < min((int)s.length(), i + 3); j++) {
            string part = s.substr(i, j - i + 1);
            if ((part.length() > 1 && part[0] == '0') || stoi(part) > 255) continue;
            backtrack(s, j + 1, curr + part + ".", dots + 1, res);
        }
    }
};

