class Solution:
    def combinationSum3(self, k: int, n: int) -> List[List[int]]:
        res = []
        def backtrack(start, curr, target):
            if len(curr) == k and target == 0:
                res.append(curr.copy())
                return
            for i in range(start, 10):
                curr.append(i)
                backtrack(i + 1, curr, target - i)
                curr.pop()
        backtrack(1, [], n)
        return res

