    void backtrack(string& s, int index, vector<string>& res) {
        if (index == s.length()) {
            res.push_back(s);
            return;
        }
        if (isalpha(s[index])) {
            s[index] = tolower(s[index]);
            backtrack(s, index + 1, res);
            s[index] = toupper(s[index]);
            backtrack(s, index + 1, res);
        } else {
            backtrack(s, index + 1, res);
        }
    }
};

