class Solution:
    def getMaximumGold(self, grid: List[List[int]]) -> int:
        def dfs(i, j):
            if i < 0 or i >= len(grid) or j < 0 or j >= len(grid[0]) or grid[i][j] == 0:
                return 0
            temp = grid[i][j]
            grid[i][j] = 0
            res = temp + max(
                dfs(i + 1, j),
                dfs(i - 1, j),
                dfs(i, j + 1),
                dfs(i, j - 1)
            )
            grid[i][j] = temp
            return res
        ans = 0
        for i in range(len(grid)):
            for j in range(len(grid[0])):
                if grid[i][j] != 0:
                    ans = max(ans, dfs(i, j))
        return ans

