class Solution:
    def sequentialDigits(self, low: int, high: int) -> List[int]:
        res = []
        def backtrack(curr, digit):
            num = curr * 10 + digit
            if num >= low and num <= high:
                res.append(num)
            if num > high or digit == 9:
                return
            backtrack(num, digit + 1)
        for i in range(1, 10):
            backtrack(0, i)
        res.sort()
        return res

