class Solution:
    def maxUniqueSplit(self, s: str) -> int:
        def backtrack(i, seen):
            if i == len(s): return 0
            res = -1
            for j in range(i + 1, len(s) + 1):
                sub = s[i:j]
                if sub not in seen:
                    seen.add(sub)
                    nxt = backtrack(j, seen)
                    if nxt != -1:
                        res = max(res, 1 + nxt)
                    seen.remove(sub)
            return res
        return backtrack(0, set())

