public:
    int totalNQueens(int n) {
        int res = 0;
        vector<bool> col(n, false);
        vector<bool> diag1(2 * n, false);
        vector<bool> diag2(2 * n, false);
        backtrack(0, n, col, diag1, diag2, res);
        return res;
    }
private:
    void backtrack(int r, int n, vector<bool>& col, vector<bool>& diag1, vector<bool>& diag2, int& res) {
        if (r == n) {
            res++;
            return;
        }
        for (int c = 0; c < n; c++) {
            if (col[c] || diag1[r + c] || diag2[r - c + n]) continue;
            col[c] = diag1[r + c] = diag2[r - c + n] = true;
            backtrack(r + 1, n, col, diag1, diag2, res);
            col[c] = diag1[r + c] = diag2[r - c + n] = false;
        }
    }
};

