class TrieNode {
public:
    vector<TrieNode*> children;
    string word;
    TrieNode() : children(26, nullptr), word("") {}
};
class Solution {
public:
    vector<string> findWords(vector<vector<char>>& board, vector<string>& words) {
        TrieNode* root = new TrieNode();
        for (string word : words) {
            TrieNode* node = root;
            for (char c : word) {
                if (!node->children[c - 'a']) node->children[c - 'a'] = new TrieNode();
                node = node->children[c - 'a'];
            }
            node->word = word;
        }
        vector<string> res;
        for (int i = 0; i < board.size(); i++) {
            for (int j = 0; j < board[0].size(); j++) {
                dfs(board, i, j, root, res);
            }
        }
        return res;
    }
private:
    void dfs(vector<vector<char>>& board, int i, int j, TrieNode* p, vector<string>& res) {
        if (i < 0 || i >= board.size() || j < 0 || j >= board[0].size() || board[i][j] == '#' || !p->children[board[i][j] - 'a']) return;
        char c = board[i][j];
        p = p->children[c - 'a'];
        if (p->word != "") {
            res.push_back(p->word);
            p->word = "";
        }
        board[i][j] = '#';
        dfs(board, i + 1, j, p, res);
        dfs(board, i - 1, j, p, res);
        dfs(board, i, j + 1, p, res);
        dfs(board, i, j - 1, p, res);
        board[i][j] = c;
    }
};

