class TrieNode:
    def __init__(self):
        self.children = {}
        self.isWord = False

class Solution:
    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:
        root = TrieNode()
        for w in words:
            cur = root
            for c in w:
                if c not in cur.children:
                    cur.children[c] = TrieNode()
                cur = cur.children[c]
            cur.isWord = True

        res, visit = set(), set()
        def dfs(r, c, node, word):
            if (r < 0 or r >= len(board) or c < 0 or c >= len(board[0]) or
                (r, c) in visit or board[r][c] not in node.children):
                return
            visit.add((r, c))
            node = node.children[board[r][c]]
            word += board[r][c]
            if node.isWord:
                res.add(word)
            dfs(r + 1, c, node, word)
            dfs(r - 1, c, node, word)
            dfs(r, c + 1, node, word)
            dfs(r, c - 1, node, word)
            visit.remove((r, c))

        for i in range(len(board)):
            for j in range(len(board[0])):
                dfs(i, j, root, "")
        return list(res)

