class Solution {
public:
    int distributeCookies(vector<int>& cookies, int k) {
        vector<int> children(k, 0);
        int ans = INT_MAX;
        backtrack(cookies, 0, children, ans);
        return ans;
    }
private:
    void backtrack(vector<int>& cookies, int i, vector<int>& children, int& ans) {
        if (i == cookies.size()) {
            int maxVal = 0;
            for (int val : children) maxVal = max(maxVal, val);
            ans = min(ans, maxVal);
            return;
        }
        for (int j = 0; j < children.size(); j++) {
            children[j] += cookies[i];
            backtrack(cookies, i + 1, children, ans);
            children[j] -= cookies[i];
            if (children[j] == 0) break;
        }
    }
};

