    private void backtrack(int[] cookies, int i, int[] children) {
        if (i == cookies.length) {
            int max = 0;
            for (int val : children) max = Math.max(max, val);
            ans = Math.min(ans, max);
            return;
        }
        for (int j = 0; j < children.length; j++) {
            children[j] += cookies[i];
            backtrack(cookies, i + 1, children);
            children[j] -= cookies[i];
            if (children[j] == 0) break;
        }
    }
}

