class Solution:
    def distributeCookies(self, cookies: List[int], k: int) -> int:
        self.ans = float('inf')
        children = [0] * k
        def backtrack(i):
            if i == len(cookies):
                self.ans = min(self.ans, max(children))
                return
            for j in range(k):
                children[j] += cookies[i]
                if max(children) < self.ans:
                    backtrack(i + 1)
                children[j] -= cookies[i]
                if children[j] == 0:
                    break
        backtrack(0)
        return self.ans

