class Solution {
public:
    vector<int> constructDistancedSequence(int n) {
        vector<int> res(n * 2 - 1, 0);
        vector<bool> used(n + 1, false);
        backtrack(res, used, 0, n);
        return res;
    }
private:
    bool backtrack(vector<int>& res, vector<bool>& used, int i, int n) {
        if (i == res.size()) return true;
        if (res[i] != 0) return backtrack(res, used, i + 1, n);
        for (int num = n; num >= 1; num--) {
            if (used[num]) continue;
            if (num > 1 && (i + num >= res.size() || res[i + num] != 0)) continue;
            res[i] = num;
            if (num > 1) res[i + num] = num;
            used[num] = true;
            if (backtrack(res, used, i + 1, n)) return true;
            res[i] = 0;
            if (num > 1) res[i + num] = 0;
            used[num] = false;
        }
        return false;
    }
};

