class Solution:
    def isSolvable(self, words: List[str], result: str) -> bool:
        words.append(result)
        R, C = len(words), max(map(len, words))
        char2digit, digit2char = {}, {}
        def dfs(c, r, carry):
            if c == C:
                return carry == 0
            if r == R:
                return carry % 10 == 0 and dfs(c + 1, 0, carry // 10)
            word = words[r]
            if c >= len(word):
                return dfs(c, r + 1, carry)
            ch = word[~c]
            sign = 1 if r < R - 1 else -1
            if ch in char2digit:
                if char2digit[ch] == 0 and c == len(word) - 1 and len(word) > 1:
                    return False
                return dfs(c, r + 1, carry + sign * char2digit[ch])
            for d in range(10):
                if d not in digit2char:
                    if d == 0 and c == len(word) - 1 and len(word) > 1:
                        continue
                    char2digit[ch] = d
                    digit2char[d] = ch
                    if dfs(c, r + 1, carry + sign * d):
                        return True
                    del char2digit[ch]
                    del digit2char[d]
            return False
        return dfs(0, 0, 0)

