public:
    string findDifferentBinaryString(vector<string>& nums) {
        unordered_set<string> s(nums.begin(), nums.end());
        string res = "";
        backtrack(nums.size(), "", s, res);
        return res;
    }
private:
    bool backtrack(int n, string curr, unordered_set<string>& s, string& res) {
        if (curr.length() == n) {
            if (s.find(curr) == s.end()) {
                res = curr;
                return true;
            }
            return false;
        }
        if (backtrack(n, curr + "0", s, res)) return true;
        if (backtrack(n, curr + "1", s, res)) return true;
        return false;
    }
};

