        int[] dp = new int[envelopes.length];
        int len = 0;
        for(int[] env : envelopes) {
            int index = Arrays.binarySearch(dp, 0, len, env[1]);
            if(index < 0) index = -(index + 1);
            dp[index] = env[1];
            if(index == len) len++;
        }
        return len;
    }
}

