        int hold = Integer.MIN_VALUE, sell = 0, rest = 0;
        for(int p : prices) {
            int prevSell = sell;
            sell = hold + p;
            hold = Math.max(hold, rest - p);
            rest = Math.max(rest, prevSell);
        }
        return Math.max(sell, rest);
    }
}

