class Solution {
public:
    int maxProfit(int k, vector<int>& prices) {
        if(prices.empty() || k == 0) return 0;
        if(k >= prices.size()/2) {
            int res = 0;
            for(int i=1; i<prices.size(); i++) if(prices[i] > prices[i-1]) res += prices[i] - prices[i-1];
            return res;
        }
        vector<int> buy(k+1, INT_MAX), sell(k+1, 0);
        for(int p : prices) {
            for(int i=1; i<=k; i++) {
                buy[i] = min(buy[i], p - sell[i-1]);
                sell[i] = max(sell[i], p - buy[i]);
            }
        }
        return sell[k];
    }
};

