class Solution {
public:
    int minCut(string s) {
        int n = s.size();
        vector<int> cuts(n);
        vector<vector<bool>> pal(n, vector<bool>(n, false));
        for(int i=0; i<n; i++) {
            int minC = i;
            for(int j=0; j<=i; j++) {
                if(s[j] == s[i] && (i - j < 2 || pal[j+1][i-1])) {
                    pal[j][i] = true;
                    minC = j == 0 ? 0 : min(minC, cuts[j-1] + 1);
                }
            }
            cuts[i] = minC;
        }
        return cuts[n-1];
    }
};

