        if not node: return node
        m = {node: Node(node.val)}
        q = deque([node])
        while q:
            n = q.popleft()
            for neighbor in n.neighbors:
                if neighbor not in m:
                    m[neighbor] = Node(neighbor.val)
                    q.append(neighbor)
                m[n].neighbors.append(m[neighbor])
        return m[node]

