        for(int j=0; j<n; ++j) { dfs(heights, p, 0, j); dfs(heights, a, m-1, j); }
        vector<vector<int>> res;
        for(int i=0; i<m; ++i) for(int j=0; j<n; ++j) if(p[i][j] && a[i][j]) res.push_back({i, j});
