        m, n = len(heights), len(heights[0])
        p, a = set(), set()
        def dfs(r, c, vis):
            vis.add((r, c))
            for dr, dc in [(-1,0), (1,0), (0,-1), (0,1)]:
                nr, nc = r+dr, c+dc
                if 0<=nr<m and 0<=nc<n and (nr, nc) not in vis and heights[nr][nc] >= heights[r][c]:
                    dfs(nr, nc, vis)
        for i in range(m):
            dfs(i, 0, p)
            dfs(i, n-1, a)
        for j in range(n):
            dfs(0, j, p)
            dfs(m-1, j, a)
        return list(p & a)

