        if endWord not in dict: return 0
        q = deque([(beginWord, 1)])
        while q:
            word, length = q.popleft()
            if word == endWord: return length
            for i in range(len(word)):
                for c in 'abcdefghijklmnopqrstuvwxyz':
                    nxt = word[:i] + c + word[i+1:]
                    if nxt in dict:
                        dict.remove(nxt)
                        q.append((nxt, length+1))
        return 0

