        for(Map.Entry<String, Double> e : adj.get(a).entrySet()) {
            if(!vis.contains(e.getKey())) {
                double res = dfs(e.getKey(), b, vis);
                if(res != -1.0) return res * e.getValue();
            }
        }
        return -1.0;
