class Solution:
    def calcEquation(self, eqs: List[List[str]], vals: List[float], qs: List[List[str]]) -> List[float]:
        adj = defaultdict(dict)
        for (a, b), v in zip(eqs, vals):
            adj[a][b] = v
            adj[b][a] = 1.0 / v
        def dfs(a, b, vis):
            if a not in adj or b not in adj: return -1.0
            if a == b: return 1.0
            vis.add(a)
            for nxt, v in adj[a].items():
                if nxt not in vis:
                    res = dfs(nxt, b, vis)
                    if res != -1.0: return res * v
            return -1.0
        return [dfs(a, b, set()) for a, b in qs]

