        parent = list(range(len(edges) + 1))
        def find(i):
            if parent[i] == i: return i
            parent[i] = find(parent[i])
            return parent[i]
        for u, v in edges:
            pu, pv = find(u), find(v)
            if pu == pv: return [u, v]
            parent[pu] = pv
        return []

