class Solution {
public:
    double maxProbability(int n, vector<vector<int>>& edges, vector<double>& succProb, int start, int end) {
        vector<vector<pair<int, double>>> adj(n);
        for(int i=0; i<edges.size(); i++) {
            adj[edges[i][0]].push_back({edges[i][1], succProb[i]});
            adj[edges[i][1]].push_back({edges[i][0], succProb[i]});
        }
        vector<double> probs(n, 0.0); probs[start] = 1.0;
        priority_queue<pair<double, int>> pq; pq.push({1.0, start});
        while(!pq.empty()) {
            auto [p, u] = pq.top(); pq.pop();
            if(u == end) return p;
            if(p < probs[u]) continue;
            for(auto& edge : adj[u]) {
                int v = edge.first; double prob = edge.second;
                if(p * prob > probs[v]) { probs[v] = p * prob; pq.push({probs[v], v}); }
            }
        }
        return 0.0;
    }
};

