class Solution {
    public double maxProbability(int n, int[][] edges, double[] succProb, int start, int end) {
        List<double[]>[] adj = new ArrayList[n];
        for(int i=0; i<n; i++) adj[i] = new ArrayList<>();
        for(int i=0; i<edges.length; i++) {
            adj[edges[i][0]].add(new double[]{edges[i][1], succProb[i]});
            adj[edges[i][1]].add(new double[]{edges[i][0], succProb[i]});
        }
        double[] probs = new double[n]; probs[start] = 1.0;
        PriorityQueue<double[]> pq = new PriorityQueue<>((a, b) -> Double.compare(b[0], a[0]));
        pq.add(new double[]{1.0, start});
        while(!pq.isEmpty()) {
            double[] curr = pq.poll();
            double p = curr[0]; int u = (int)curr[1];
            if(u == end) return p;
            if(p < probs[u]) continue;
            for(double[] edge : adj[u]) {
                int v = (int)edge[0]; double prob = edge[1];
                if(p * prob > probs[v]) { probs[v] = p * prob; pq.add(new double[]{probs[v], v}); }
            }
        }
        return 0.0;
    }
}

