class Solution {
public:
    int openLock(vector<string>& deadends, string target) {
        unordered_set<string> dead(deadends.begin(), deadends.end());
        if(dead.count("0000")) return -1;
        queue<string> q; q.push("0000"); dead.insert("0000");
        int steps = 0;
        while(!q.empty()) {
            int sz = q.size();
            while(sz--) {
                string s = q.front(); q.pop();
                if(s == target) return steps;
                for(int i=0; i<4; i++) {
                    for(int d : {-1, 1}) {
                        string next = s;
                        next[i] = (next[i] - '0' + d + 10) % 10 + '0';
                        if(!dead.count(next)) { dead.insert(next); q.push(next); }
                    }
                }
            }
            steps++;
        }
        return -1;
    }
};

