class Solution:
    def openLock(self, deadends: List[str], target: str) -> int:
        dead = set(deadends)
        if "0000" in dead: return -1
        q = deque([("0000", 0)]); dead.add("0000")
        while q:
            s, steps = q.popleft()
            if s == target: return steps
            for i in range(4):
                for d in [-1, 1]:
                    nxt = s[:i] + str((int(s[i]) + d) % 10) + s[i+1:]
                    if nxt not in dead:
                        dead.add(nxt)
                        q.append((nxt, steps + 1))
        return -1

