class Solution {
public:
    int snakesAndLadders(vector<vector<int>>& board) {
        int n = board.size();
        auto get = [&](int s) -> pair<int,int> {
            int r = n - 1 - (s - 1) / n, c = (s - 1) % n;
            if ((n - 1 - r) % 2 != 0) c = n - 1 - c;
            return {r, c};
        };
        queue<int> q; q.push(1);
        vector<bool> vis(n*n+1, false); vis[1] = true;
        int moves = 0;
        while(!q.empty()) {
            int sz = q.size();
            while(sz--) {
                int curr = q.front(); q.pop();
                if(curr == n*n) return moves;
                for(int i=1; i<=6; i++) {
                    if(curr + i > n*n) break;
                    auto [r, c] = get(curr + i);
                    int next = board[r][c] == -1 ? curr + i : board[r][c];
                    if(!vis[next]) { vis[next] = true; q.push(next); }
                }
            }
            moves++;
        }
        return -1;
    }
};

