class Solution:
    def snakesAndLadders(self, board: List[List[int]]) -> int:
        n = len(board)
        def get(s):
            r, c = divmod(s - 1, n)
            if r % 2 == 1: c = n - 1 - c
            return n - 1 - r, c
        q = deque([(1, 0)])
        vis = set([1])
        while q:
            curr, moves = q.popleft()
            if curr == n * n: return moves
            for i in range(1, 7):
                if curr + i > n * n: break
                r, c = get(curr + i)
                nxt = board[r][c] if board[r][c] != -1 else curr + i
                if nxt not in vis:
                    vis.add(nxt)
                    q.append((nxt, moves + 1))
        return -1

