class Solution:
    def maxDistance(self, grid: List[List[int]]) -> int:
        n = len(grid)
        q = deque()
        for i in range(n):
            for j in range(n):
                if grid[i][j]: q.append((i, j))
        if len(q) == 0 or len(q) == n * n: return -1
        res = -1
        while q:
            for _ in range(len(q)):
                r, c = q.popleft()
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0<=nr<n and 0<=nc<n and grid[nr][nc]==0:
                        grid[nr][nc] = 1
                        q.append((nr, nc))
            res += 1
        return res

class Solution: def leastInterval(self, tasks: List[str], n: int) -> int:
  counts = collections.Counter(tasks)
  maxCount = max(counts.values())
  ans = (maxCount-1)*(n+1)
  for count in counts.values():
   if count == maxCount: ans += 1
  return max(len(tasks), ans)

class Solution: def canCompleteCircuit(self, gas: List[int], cost: List[int]) -> int:
  total = current = start = 0
  for i in range(len(gas)):
   total += gas[i] - cost[i]
   current += gas[i] - cost[i]
   if current < 0:
    start = i + 1
    current = 0
  return -1 if total < 0 else start

class Solution: def candy(self, ratings: List[int]) -> int:
  n = len(ratings)
  candies = [1] * n
  for i in range(1, n):
   if ratings[i] > ratings[i-1]: candies[i] = candies[i-1] + 1
  for i in range(n-2, -1, -1):
   if ratings[i] > ratings[i+1]: candies[i] = max(candies[i], candies[i+1] + 1)
  return sum(candies)

class Solution: def findMinArrowShots(self, points: List[List[int]]) -> int:
  if not points: return 0
  points.sort(key=lambda x: x[1])
  arrows = 1
  end = points[0][1]
  for p in points:
   if p[0] > end:
    arrows += 1
    end = p[1]
  return arrows

class Solution: def eraseOverlapIntervals(self, intervals: List[List[int]]) -> int:
  intervals.sort(key=lambda x: x[1])
  ans = 0
  end = float('-inf')
  for inv in intervals:
   if inv[0] >= end: end = inv[1]
   else: ans += 1
  return ans

class Solution: def reconstructQueue(self, people: List[List[int]]) -> List[List[int]]:
  people.sort(key=lambda x: (-x[0], x[1]))
  res = []
  for p in people:
   res.insert(p[1], p)
  return res

class Solution: def partitionLabels(self, s: str) -> List[int]:
  last = {c: i for i, c in enumerate(s)}
  res = []
  start = end = 0
  for i, c in enumerate(s):
   end = max(end, last[c])
   if i == end:
    res.append(end - start + 1)
    start = i + 1
  return res

class Solution: def isNStraightHand(self, hand: List[int], groupSize: int) -> bool:
  count = collections.Counter(hand)
  for i in sorted(count):
   if count[i] > 0:
    for j in range(groupSize)[::-1]:
     count[i + j] -= count[i]
     if count[i + j] < 0: return False
  return True

class Solution: def wiggleMaxLength(self, nums: List[int]) -> int:
  if len(nums) < 2: return len(nums)
  up, down = 1, 1
  for i in range(1, len(nums)):
   if nums[i] > nums[i-1]: up = down + 1
   elif nums[i] < nums[i-1]: down = up + 1
  return max(up, down)

class Solution: def reorganizeString(self, s: str) -> str:
  cnt = collections.Counter(s)
  pq = [(-v, k) for k, v in cnt.items()]
  heapq.heapify(pq)
  res = []
  while len(pq) > 1:
   v1, k1 = heapq.heappop(pq)
   v2, k2 = heapq.heappop(pq)
   res.extend([k1, k2])
   if v1 < -1: heapq.heappush(pq, (v1+1, k1))
   if v2 < -1: heapq.heappush(pq, (v2+1, k2))
  if pq:
   v, k = heapq.heappop(pq)
   if v < -1: return ""
   res.append(k)
  return "".join(res)

class Solution: def minDeletions(self, s: str) -> int:
  freq = collections.Counter(s)
  used = set()
  ans = 0
  for count in freq.values():
   while count > 0 and count in used:
    count -= 1
    ans += 1
   used.add(count)
  return ans

class Solution: def balancedStringSplit(self, s: str) -> int:
  balance = count = 0
  for c in s:
   balance += 1 if c == 'L' else -1
   if balance == 0: count += 1
  return count

class Solution: def maxCoins(self, piles: List[int]) -> int:
  piles.sort()
