class Solution: def breakPalindrome(self, palindrome: str) -> str:
  n = len(palindrome)
  if n == 1: return ""
  for i in range(n // 2):
   if palindrome[i] != 'a':
    return palindrome[:i] + 'a' + palindrome[i+1:]
  return palindrome[:-1] + 'b'

class Solution: def minCostToMoveChips(self, position: List[int]) -> int:
  odd = sum(p % 2 for p in position)
  return min(odd, len(position) - odd)

class Solution: def largestPerimeter(self, nums: List[int]) -> int:
  nums.sort()
  for i in range(len(nums) - 1, 1, -1):
   if nums[i - 2] + nums[i - 1] > nums[i]: return nums[i - 2] + nums[i - 1] + nums[i]
  return 0

class Solution: def minOperations(self, nums: List[int]) -> int:
  ans = 0
  prev = nums[0]
  for i in range(1, len(nums)):
   if nums[i] <= prev:
    ans += prev - nums[i] + 1
    prev += 1
   else:
    prev = nums[i]
  return ans

class Solution: def maxArea(self, h: int, w: int, horizontalCuts: List[int], verticalCuts: List[int]) -> int:
  horizontalCuts.sort()
  verticalCuts.sort()
  maxH = max(horizontalCuts[0], h - horizontalCuts[-1])
  maxW = max(verticalCuts[0], w - verticalCuts[-1])
  for i in range(1, len(horizontalCuts)): maxH = max(maxH, horizontalCuts[i] - horizontalCuts[i - 1])
  for i in range(1, len(verticalCuts)): maxW = max(maxW, verticalCuts[i] - verticalCuts[i - 1])
  return (maxH * maxW) % 1000000007

