class Solution {
    public String reorganizeString(String s) {
        Map<Character, Integer> count = new HashMap<>();
        for (char c : s.toCharArray()) count.put(c, count.getOrDefault(c, 0) + 1);
        PriorityQueue<Character> pq = new PriorityQueue<>((a, b) -> count.get(b) - count.get(a));
        pq.addAll(count.keySet());
        StringBuilder sb = new StringBuilder();
        Queue<Character> queue = new LinkedList<>();
        while (!pq.isEmpty()) {
            char curr = pq.poll();
            sb.append(curr);
            count.put(curr, count.get(curr) - 1);
            queue.offer(curr);
            if (queue.size() > 1) {
                char front = queue.poll();
                if (count.get(front) > 0) pq.offer(front);
            }
        }
        return sb.length() == s.length() ? sb.toString() : "";
    }
}

