        unordered_set<long> seen;
        pq.push(1); seen.insert(1);
        long curr = 1;
        for (int i = 0; i < n; i++) {
            curr = pq.top(); pq.pop();
            if (seen.find(curr * 2) == seen.end()) { pq.push(curr * 2); seen.insert(curr * 2); }
            if (seen.find(curr * 3) == seen.end()) { pq.push(curr * 3); seen.insert(curr * 3); }
            if (seen.find(curr * 5) == seen.end()) { pq.push(curr * 5); seen.insert(curr * 5); }
        }
        return curr;
    }
