class Solution {
public:
    bool isPossible(vector<int>& target) {
        priority_queue<long long> pq;
        long long sum = 0;
        for (int num : target) {
            sum += num;
            pq.push(num);
        }
        while (pq.top() > 1) {
            long long largest = pq.top(); pq.pop();
            long long rest = sum - largest;
            if (rest == 1) return true;
            if (rest == 0 || largest <= rest || largest % rest == 0) return false;
            long long prev = largest % rest;
            pq.push(prev);
            sum = rest + prev;
        }
        return true;
    }
};

