class Solution:
    def isPossible(self, target: List[int]) -> bool:
        if len(target) == 1:
            return target[0] == 1
        heap = [-x for x in target]
        heapq.heapify(heap)
        total = sum(target)
        while -heap[0] > 1:
            largest = -heapq.heappop(heap)
            rest = total - largest
            if rest == 1:
                return True
            if rest == 0 or largest <= rest or largest % rest == 0:
                return False
            prev = largest % rest
            heapq.heappush(heap, -prev)
            total = rest + prev
        return True

