class Solution {
    public int[] getOrder(int[][] tasks) {
        int n = tasks.length;
        int[][] extTasks = new int[n][3];
        for(int i = 0; i < n; i++) {
            extTasks[i][0] = tasks[i][0];
            extTasks[i][1] = tasks[i][1];
            extTasks[i][2] = i;
        }
        Arrays.sort(extTasks, (a, b) -> Integer.compare(a[0], b[0]));
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> {
            if(a[1] == b[1]) return Integer.compare(a[2], b[2]);
            return Integer.compare(a[1], b[1]);
        });
        int[] res = new int[n];
        int ansIdx = 0, taskIdx = 0;
        long time = 0;
        while (ansIdx < n) {
            if (pq.isEmpty() && time < extTasks[taskIdx][0]) time = extTasks[taskIdx][0];
            while (taskIdx < n && extTasks[taskIdx][0] <= time) {
                pq.offer(extTasks[taskIdx]);
                taskIdx++;
            }
            int[] curr = pq.poll();
            time += curr[1];
            res[ansIdx++] = curr[2];
        }
        return res;
    }
}

