    def mincostToHireWorkers(self, quality: List[int], wage: List[int], k: int) -> float:
        workers = sorted([(w/q, q) for w, q in zip(wage, quality)])
        res = float('inf')
        sumq = 0
        pq = []
        for ratio, q in workers:
            sumq += q
            heapq.heappush(pq, -q)
            if len(pq) > k:
                sumq += heapq.heappop(pq)
            if len(pq) == k:
                res = min(res, sumq * ratio)
        return res

