class Solution {
    public List<List<Integer>> getSkyline(int[][] buildings) {
        List<int[]> edges = new ArrayList<>();
        for (int[] b : buildings) {
            edges.add(new int[]{b[0], -b[2]});
            edges.add(new int[]{b[1], b[2]});
        }
        Collections.sort(edges, (a, b) -> {
            if (a[0] != b[0]) return a[0] - b[0];
            return a[1] - b[1];
        });
        TreeMap<Integer, Integer> map = new TreeMap<>(Collections.reverseOrder());
        map.put(0, 1);
        int prev = 0;
        List<List<Integer>> res = new ArrayList<>();
        for (int[] e : edges) {
            if (e[1] < 0) map.put(-e[1], map.getOrDefault(-e[1], 0) + 1);
            else {
                if (map.get(e[1]) == 1) map.remove(e[1]);
                else map.put(e[1], map.get(e[1]) - 1);
            }
            int curr = map.firstKey();
            if (curr != prev) {
                res.add(Arrays.asList(e[0], curr));
                prev = curr;
            }
        }
        return res;
    }
}

