class Solution {
public:
    double maxAverageRatio(vector<vector<int>>& classes, int extraStudents) {
        auto profit = [](double p, double t) {
            return (p + 1) / (t + 1) - p / t;
        };
        priority_queue<pair<double, pair<int, int>>> pq;
        for (auto& c : classes) {
            pq.push({profit(c[0], c[1]), {c[0], c[1]}});
        }
        while (extraStudents--) {
            auto top = pq.top(); pq.pop();
            int p = top.second.first + 1, t = top.second.second + 1;
            pq.push({profit(p, t), {p, t}});
        }
        double res = 0;
        while (!pq.empty()) {
            res += (double)pq.top().second.first / pq.top().second.second;
            pq.pop();
        }
        return res / classes.size();
    }
};

