            sum += num;
            pq.push(num);
        }
        double target = sum / 2, reduced = 0;
        int ops = 0;
        while (reduced < target) {
            double max_val = pq.top(); pq.pop();
            reduced += max_val / 2;
            pq.push(max_val / 2);
            ops++;
        }
        return ops;
    }
};

