class Solution:
    def longestSubarray(self, nums: List[int], limit: int) -> int:
        import collections
        maxd = collections.deque()
        mind = collections.deque()
        i = 0
        for num in nums:
            while maxd and num > maxd[-1]: maxd.pop()
            while mind and num < mind[-1]: mind.pop()
            maxd.append(num)
            mind.append(num)
            if maxd[0] - mind[0] > limit:
                if maxd[0] == nums[i]: maxd.popleft()
                if mind[0] == nums[i]: mind.popleft()
                i += 1
        return len(nums) - i

class Solution:
    def shortestSubarray(self, nums: List[int], k: int) -> int:
        import collections
        n = len(nums)
        p = [0] * (n + 1)
        for i in range(n): p[i + 1] = p[i] + nums[i]
        res = n + 1
        dq = collections.deque()
        for i in range(n + 1):
            while dq and p[i] - p[dq[0]] >= k:
                res = min(res, i - dq.popleft())
            while dq and p[i] <= p[dq[-1]]:
                dq.pop()
            dq.append(i)
        return res if res <= n else -1

