        i = 0
        for j, (charge, cost) in enumerate(zip(chargeTimes, runningCosts)):
            sum_cost += cost
            while dq and chargeTimes[dq[-1]] <= charge: dq.pop()
            dq.append(j)
            if chargeTimes[dq[0]] + (j - i + 1) * sum_cost > budget:
