        n = len(grid)
        import collections
        q = collections.deque()
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1: q.append((i, j))
        if not q or len(q) == n * n: return -1
        dist = -1
        while q:
            for _ in range(len(q)):
                r, c = q.popleft()
                for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                    nr, nc = r + dr, c + dc
