            dist += 1
        return dist

class Solution:
    def shortestBridge(self, grid: List[List[int]]) -> int:
        n = len(grid)
        import collections
        q = collections.deque()
        def dfs(r, c):
            if 0 <= r < n and 0 <= c < n and grid[r][c] == 1:
                grid[r][c] = 2
                q.append((r, c))
                dfs(r+1, c); dfs(r-1, c); dfs(r, c+1); dfs(r, c-1)
        found = False
        for i in range(n):
            if found: break
            for j in range(n):
                if grid[i][j] == 1:
                    dfs(i, j)
                    found = True
                    break
        steps = 0
        while q:
            for _ in range(len(q)):
                r, c = q.popleft()
                for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < n:
                        if grid[nr][nc] == 1: return steps
                        if grid[nr][nc] == 0:
                            grid[nr][nc] = 2
                            q.append((nr, nc))
            steps += 1
        return -1

class Solution:
    def numBusesToDestination(self, routes: List[List[int]], source: int, target: int) -> int:
        if source == target: return 0
        import collections
        adj = collections.defaultdict(list)
        for i, route in enumerate(routes):
            for stop in route:
                adj[stop].append(i)
        q = collections.deque([source])
        visited_routes = set()
        buses = 0
        while q:
            for _ in range(len(q)):
                stop = q.popleft()
                if stop == target: return buses
                for route in adj[stop]:
                    if route not in visited_routes:
                        visited_routes.add(route)
                        for next_stop in routes[route]:
                            q.append(next_stop)
            buses += 1
        return -1

class Solution:
    def medianSlidingWindow(self, nums: List[int], k: int) -> List[float]:
        import heapq
        lo, hi = [], []
        res = []
        invalid = collections.Counter()
        def balance():
            while len(lo) > len(hi) + 1:
                heapq.heappush(hi, -heapq.heappop(lo))
            while len(hi) > len(lo):
                heapq.heappush(lo, -heapq.heappop(hi))
        for i, x in enumerate(nums):
            if not lo or x <= -lo[0]:
                heapq.heappush(lo, -x)
            else:
                heapq.heappush(hi, x)
            balance()
            if i >= k - 1:
                while lo and invalid[-lo[0]] > 0:
                    invalid[-lo[0]] -= 1
                    heapq.heappop(lo)
                while hi and invalid[hi[0]] > 0:
                    invalid[hi[0]] -= 1
                    heapq.heappop(hi)
                balance()
                res.append(float(-lo[0]) if k % 2 else (-lo[0] + hi[0]) / 2.0)
                invalid[nums[i - k + 1]] += 1
        return res

