        minq = collections.deque()
        i = 0
        for num in nums:
            while len(maxq) and num > maxq[-1]: maxq.pop()
            while len(minq) and num < minq[-1]: minq.pop()
            maxq.append(num)
            minq.append(num)
            if maxq[0] - minq[0] > limit:
