        window = sorted(nums[:k])
        res = []
        for i in range(k, len(nums) + 1):
            if k % 2 == 1:
                res.append(float(window[k // 2]))
            else:
                res.append((window[k // 2 - 1] + window[k // 2]) / 2.0)
