class Solution {
public:
    bool wordPattern(string pattern, string s) {
        unordered_map<char, string> char_map;
        unordered_map<string, char> word_map;
        stringstream ss(s);
        string word;
        int i = 0, n = pattern.size();
        while (ss >> word) {
            if (i == n) return false;
            char c = pattern[i];
            if (char_map.count(c) != word_map.count(word)) return false;
            if (char_map.count(c)) {
                if (char_map[c] != word || word_map[word] != c) return false;
            } else {
                char_map[c] = word;
                word_map[word] = c;
            }
            i++;
        }
        return i == n;
    }
};

