class Solution {
    public String reverseVowels(String s) {
        char[] chars = s.toCharArray();
        int l = 0, r = s.length() - 1;
        String vowels = "aeiouAEIOU";
        while (l < r) {
            while (l < r && vowels.indexOf(chars[l]) == -1) l++;
            while (l < r && vowels.indexOf(chars[r]) == -1) r--;
            char temp = chars[l];
            chars[l++] = chars[r];
            chars[r--] = temp;
        }
        return new String(chars);
    }
}

