public:
    int longestPalindrome(string s) {
        unordered_map<char, int> counts;
        for (char c : s) counts[c]++;
        int res = 0; bool hasOdd = false;
        for (auto p : counts) {
            if (p.second % 2 == 0) res += p.second;
            else { res += p.second - 1; hasOdd = true; }
        }
        return hasOdd ? res + 1 : res;
    }
};

