class Solution {
public:
    bool checkInclusion(string s1, string s2) {
        vector<int> map1(26, 0), map2(26, 0);
        if (s1.size() > s2.size()) return false;
        for (int i = 0; i < s1.size(); i++) {
            map1[s1[i] - 'a']++;
            map2[s2[i] - 'a']++;
        }
        for (int i = 0; i < s2.size() - s1.size(); i++) {
            if (map1 == map2) return true;
            map2[s2[i + s1.size()] - 'a']++;
            map2[s2[i] - 'a']--;
        }
        return map1 == map2;
    }
};

