class Solution:
    def zigzagLevelOrder(self, root: Optional[TreeNode]) -> List[List[int]]:
        if not root: return []
        res, q = [], collections.deque([root])
        ltr = True
        while q:
            n = len(q)
            level = [0] * n
            for i in range(n):
                node = q.popleft()
                idx = i if ltr else (n - 1 - i)
                level[idx] = node.val
                if node.left: q.append(node.left)
                if node.right: q.append(node.right)
            ltr = not ltr
            res.append(level)
        return res

