    def addWord(self, word: str):
        n = self.root
        for c in word:
            if c not in n: n[c] = {}
            n = n[c]
        n['$'] = True
    def search(self, word: str) -> bool:
        def dfs(i, n):
            if i == len(word): return '$' in n
            if word[i] != '.':
                return word[i] in n and dfs(i+1, n[word[i]])
            return any(dfs(i+1, n[nxt]) for nxt in n if nxt != '$')
        return dfs(0, self.root)

