class Solution {
    struct Node { Node* c[26]={0}; string* w=0; };
public:
    vector<string> findWords(vector<vector<char>>& board, vector<string>& words) {
        Node* root = new Node();
        for(auto& word: words) {
            Node* n = root;
            for(char c: word) {
                if(!n->c[c-'a']) n->c[c-'a'] = new Node();
                n = n->c[c-'a'];
            }
            n->w = &word;
        }
        vector<string> res;
        for(int i=0; i<board.size(); i++)
            for(int j=0; j<board[0].size(); j++)
                dfs(board, i, j, root, res);
        return res;
    }
    void dfs(vector<vector<char>>& b, int i, int j, Node* n, vector<string>& res) {
        if(i<0||j<0||i>=b.size()||j>=b[0].size()||b[i][j]=='#') return;
        char c = b[i][j];
        if(!n->c[c-'a']) return;
        n = n->c[c-'a'];
        if(n->w) { res.push_back(*(n->w)); n->w = 0; }
        b[i][j] = '#';
        dfs(b, i+1, j, n, res); dfs(b, i-1, j, n, res);
        dfs(b, i, j+1, n, res); dfs(b, i, j-1, n, res);
        b[i][j] = c;
    }
};

