class Solution:
    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:
        root = {}
        for w in words:
            n = root
            for c in w:
                if c not in n: n[c] = {}
                n = n[c]
            n['$'] = w
        res = []
        def dfs(i, j, n):
            c = board[i][j]
            if c not in n: return
            n = n[c]
            if '$' in n:
                res.append(n['$'])
                del n['$']
            board[i][j] = '#'
            for x, y in ((i+1,j),(i-1,j),(i,j+1),(i,j-1)):
                if 0 <= x < len(board) and 0 <= y < len(board[0]) and board[x][y] != '#':
                    dfs(x, y, n)
            board[i][j] = c
            if not n: del n
        for i in range(len(board)):
            for j in range(len(board[0])):
                dfs(i, j, root)
        return res

