class Solution {
    struct Node { Node* c[2]={0}; };
public:
    int findMaximumXOR(vector<int>& nums) {
        Node* root = new Node();
        for(int x: nums) {
            Node* n = root;
            for(int i=31; i>=0; i--) {
                int b = (x>>i)&1;
                if(!n->c[b]) n->c[b] = new Node();
                n = n->c[b];
            }
        }
        int mx = 0;
        for(int x: nums) {
            Node* n = root;
            int cur = 0;
            for(int i=31; i>=0; i--) {
                int b = (x>>i)&1;
                if(n->c[1-b]) { cur |= (1<<i); n = n->c[1-b]; }
                else n = n->c[b];
            }
            mx = max(mx, cur);
        }
        return mx;
    }
};

