class Solution:
    def findMaximumXOR(self, nums: List[int]) -> int:
        root = {}
        for x in nums:
            n = root
            for i in range(31, -1, -1):
                b = (x >> i) & 1
                if b not in n: n[b] = {}
                n = n[b]
        mx = 0
        for x in nums:
            n = root; cur = 0
            for i in range(31, -1, -1):
                b = (x >> i) & 1
                if 1-b in n:
                    cur |= (1 << i)
                    n = n[1-b]
                else:
                    n = n[b]
            mx = max(mx, cur)
        return mx

