class Solution {
    struct Node { Node* c[26]={0}; string* w=0; };
public:
    string replaceWords(vector<string>& dict, string sentence) {
        Node* root = new Node();
        for(auto& w: dict) {
            Node* n = root;
            for(char ch: w) {
                if(!n->c[ch-'a']) n->c[ch-'a'] = new Node();
                n = n->c[ch-'a'];
            }
            n->w = &w;
        }
        stringstream ss(sentence);
        string word, res="";
        while(ss >> word) {
            Node* n = root;
            for(char ch: word) {
                if(!n->c[ch-'a'] || n->w) break;
                n = n->c[ch-'a'];
            }
            res += (n->w ? *(n->w) : word) + " ";
        }
        res.pop_back();
        return res;
    }
};

