class Solution {
    struct Node { Node* c[26]={0}; int idx=-1; vector<int> pal; };
    bool isPal(string& w, int i, int j) {
        while(i<j) if(w[i++] != w[j--]) return false;
        return true;
    }
public:
    vector<vector<int>> palindromePairs(vector<string>& words) {
        Node* root = new Node();
        for(int i=0; i<words.size(); i++) {
            Node* n = root;
            string w = words[i];
            reverse(w.begin(), w.end());
            for(int j=0; j<w.size(); j++) {
                if(isPal(w, j, w.size()-1)) n->pal.push_back(i);
                if(!n->c[w[j]-'a']) n->c[w[j]-'a'] = new Node();
                n = n->c[w[j]-'a'];
            }
            n->idx = i;
            n->pal.push_back(i);
        }
        vector<vector<int>> res;
        for(int i=0; i<words.size(); i++) {
            Node* n = root;
            string w = words[i];
            for(int j=0; j<w.size(); j++) {
                if(n->idx != -1 && n->idx != i && isPal(w, j, w.size()-1))
                    res.push_back({i, n->idx});
                n = n->c[w[j]-'a'];
                if(!n) break;
            }
            if(n) for(int j: n->pal) if(i != j) res.push_back({i, j});
        }
        return res;
    }
};

