    }
    public List<List<Integer>> palindromePairs(String[] words) {
        Node root = new Node();
        for(int i=0; i<words.length; i++) {
            Node n = root;
            String w = new StringBuilder(words[i]).reverse().toString();
            for(int j=0; j<w.length(); j++) {
                if(isPal(w, j, w.length()-1)) n.pal.add(i);
                if(n.c[w.charAt(j)-'a'] == null) n.c[w.charAt(j)-'a'] = new Node();
                n = n.c[w.charAt(j)-'a'];
            }
            n.idx = i; n.pal.add(i);
        }
        List<List<Integer>> res = new ArrayList<>();
        for(int i=0; i<words.length; i++) {
            Node n = root;
            String w = words[i];
            for(int j=0; j<w.length(); j++) {
                if(n.idx != -1 && n.idx != i && isPal(w, j, w.length()-1))
                    res.add(Arrays.asList(i, n.idx));
                n = n.c[w.charAt(j)-'a'];
                if(n == null) break;
            }
            if(n != null) for(int j: n.pal) if(i != j) res.add(Arrays.asList(i, j));
        }
        return res;
    }
}

