class Solution:
    def palindromePairs(self, words: List[str]) -> List[List[int]]:
        def is_pal(w): return w == w[::-1]
        root = {}
        for i, w in enumerate(words):
            n = root
            w_rev = w[::-1]
            for j in range(len(w_rev)):
                if is_pal(w_rev[j:]):
                    n.setdefault('pal', []).append(i)
                n = n.setdefault(w_rev[j], {})
            n['idx'] = i
            n.setdefault('pal', []).append(i)
        res = []
        for i, w in enumerate(words):
            n = root
            for j in range(len(w)):
                if 'idx' in n and n['idx'] != i and is_pal(w[j:]):
                    res.append([i, n['idx']])
                if w[j] not in n: break
                n = n[w[j]]
            else:
                for j in n.get('pal', []):
                    if i != j: res.append([i, j])
        return res

