class MagicDictionary:
    def __init__(self): self.trie = {}
    def buildDict(self, dictionary: List[str]) -> None:
        for w in dictionary:
            n = self.trie
            for c in w:
                if c not in n: n[c] = {}
                n = n[c]
            n['$'] = True
    def search(self, searchWord: str) -> bool:
        def dfs(w, i, n, changed):
            if i == len(w): return '$' in n and changed
            if not changed:
                for c in n:
                    if c != '$' and c != w[i] and dfs(w, i+1, n[c], True):
                        return True
            if w[i] in n:
                return dfs(w, i+1, n[w[i]], changed)
            return False
        return dfs(searchWord, 0, self.trie, False)

