    int minimumLengthEncoding(vector<string>& words) {
        Node* root = new Node();
        unordered_map<Node*, int> leaves;
        for(auto& w: unordered_set<string>(words.begin(), words.end())) {
            Node* n = root;
            for(int i=w.size()-1; i>=0; i--) {
                if(!n->c[w[i]-'a']) { n->c[w[i]-'a'] = new Node(); n->count++; }
                n = n->c[w[i]-'a'];
            }
            leaves[n] = w.size() + 1;
        }
        int ans = 0;
        for(auto& pair: leaves) if(pair.first->count == 0) ans += pair.second;
