        int[][] q = new int[queries.length][3];
        for(int i=0; i<queries.length; i++) { q[i][0]=queries[i][0]; q[i][1]=queries[i][1]; q[i][2]=i; }
        Arrays.sort(q, (a, b) -> a[1] - b[1]);
        int[] res = new int[queries.length];
        int j = 0;
        for(int[] p: q) {
            while(j < nums.length && nums[j] <= p[1]) insert(nums[j++]);
            res[p[2]] = query(p[0]);
        }
