class Solution:
    def maximizeXor(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        nums.sort()
        q = sorted([(m, x, i) for i, (x, m) in enumerate(queries)])
        root = {}
        res = [-1] * len(queries)
        j = 0
        for m, x, i in q:
            while j < len(nums) and nums[j] <= m:
                n = root
                for bit in range(31, -1, -1):
                    b = (nums[j] >> bit) & 1
                    if b not in n: n[b] = {}
                    n = n[b]
                j += 1
            if not root: continue
            n = root; mx = 0
            for bit in range(31, -1, -1):
                b = (x >> bit) & 1
                if 1-b in n:
                    mx |= (1 << bit)
                    n = n[1-b]
                else:
                    n = n[b]
            res[i] = mx
        return res

