class AutocompleteSystem {
    struct Node { Node* c[128]={0}; unordered_map<string, int> counts; };
    Node* root = new Node();
    Node* curr = root;
    string curStr = "";
    void add(string s, int count) {
        Node* n = root;
        for(char ch: s) {
            if(!n->c[ch]) n->c[ch] = new Node();
            n = n->c[ch];
            n->counts[s] += count;
        }
    }
public:
    AutocompleteSystem(vector<string>& sentences, vector<int>& times) {
        for(int i=0; i<sentences.size(); i++) add(sentences[i], times[i]);
    }
    vector<string> input(char c) {
        if(c == '#') { add(curStr, 1); curStr = ""; curr = root; return {}; }
        curStr += c;
        if(curr) curr = curr->c[c];
        if(!curr) return {};
        auto cmp = [](pair<string,int>& a, pair<string,int>& b) {
            return a.second == b.second ? a.first > b.first : a.second < b.second;
        };
        priority_queue<pair<string,int>, vector<pair<string,int>>, decltype(cmp)> pq(cmp);
        for(auto& p: curr->counts) pq.push(p);
        vector<string> res;
        for(int i=0; i<3 && !pq.empty(); i++) { res.push_back(pq.top().first); pq.pop(); }
        return res;
    }
};

