class AutocompleteSystem {
    class Node { Node[] c = new Node[128]; Map<String, Integer> counts = new HashMap<>(); }
    Node root = new Node(), curr = root;
    StringBuilder curStr = new StringBuilder();
    void add(String s, int count) {
        Node n = root;
        for(char ch: s.toCharArray()) {
            if(n.c[ch] == null) n.c[ch] = new Node();
            n = n.c[ch];
            n.counts.put(s, n.counts.getOrDefault(s, 0) + count);
        }
    }
    public AutocompleteSystem(String[] sentences, int[] times) {
        for(int i=0; i<sentences.length; i++) add(sentences[i], times[i]);
    }
    public List<String> input(char c) {
        if(c == '#') { add(curStr.toString(), 1); curStr.setLength(0); curr = root; return new ArrayList<>(); }
        curStr.append(c);
        if(curr != null) curr = curr.c[c];
        if(curr == null) return new ArrayList<>();
        PriorityQueue<Map.Entry<String, Integer>> pq = new PriorityQueue<>(
            (a, b) -> a.getValue().equals(b.getValue()) ? a.getKey().compareTo(b.getKey()) : b.getValue() - a.getValue()
        );
        pq.addAll(curr.counts.entrySet());
        List<String> res = new ArrayList<>();
        for(int i=0; i<3 && !pq.isEmpty(); i++) res.add(pq.poll().getKey());
        return res;
    }
}

