class AutocompleteSystem:
    def __init__(self, sentences: List[str], times: List[int]):
        self.trie = {}
        self.curStr = ""
        self.curr = self.trie
        for s, t in zip(sentences, times): self.add(s, t)
    def add(self, s, count):
        n = self.trie
        for c in s:
            if c not in n: n[c] = {'$': collections.defaultdict(int)}
            n = n[c]
            n['$'][s] += count
    def input(self, c: str) -> List[str]:
        if c == '#':
            self.add(self.curStr, 1)
            self.curStr = ""
            self.curr = self.trie
            return []
        self.curStr += c
        if self.curr: self.curr = self.curr.get(c)
        if not self.curr: return []
        counts = self.curr['$']
        return sorted(counts.keys(), key=lambda x: (-counts[x], x))[:3]

