class Solution {
    class Node { Node[] c = new Node[26]; int count = 0; }
    void insert(Node root, String w) {
        Node n = root;
        for(char ch: w.toCharArray()) {
            if(n.c[ch-'a'] == null) n.c[ch-'a'] = new Node();
            n = n.c[ch-'a'];
        }
        n.count++;
    }
    int search(Node n, boolean hasFirst, String p, char first) {
        if(n == null) return 0;
        int res = hasFirst ? n.count : 0;
        for(char ch: p.toCharArray()) {
            if(n.c[ch-'a'] != null) res += search(n.c[ch-'a'], hasFirst || (ch == first), p, first);
        }
        return res;
    }
    public List<Integer> findNumOfValidWords(String[] words, String[] puzzles) {
        Node root = new Node();
        for(String w: words) {
            int mask = 0;
            for(char ch: w.toCharArray()) mask |= (1<<(ch-'a'));
            if(Integer.bitCount(mask) <= 7) {
                StringBuilder sb = new StringBuilder();
                for(int i=0; i<26; i++) if((mask&(1<<i)) > 0) sb.append((char)('a'+i));
                insert(root, sb.toString());
            }
        }
        List<Integer> res = new ArrayList<>();
        for(String p: puzzles) {
            char[] s = p.toCharArray();
            Arrays.sort(s);
            res.add(search(root, false, new String(s), p.charAt(0)));
        }
        return res;
    }
}

