class Solution:
    def findNumOfValidWords(self, words: List[str], puzzles: List[str]) -> List[int]:
        root = {}
        for w in words:
            chars = sorted(set(w))
            if len(chars) <= 7:
                n = root
                for c in chars:
                    if c not in n: n[c] = {}
                    n = n[c]
                n['$'] = n.get('$', 0) + 1
        def search(n, hasFirst, p, first):
            if not n: return 0
            res = n.get('$', 0) if hasFirst else 0
            for c in p:
                if c in n:
                    res += search(n[c], hasFirst or (c == first), p, first)
            return res
        res = []
        for p in puzzles:
            res.append(search(root, False, sorted(p), p[0]))
        return res

