class Solution {
    struct Node { map<string, Node*> c; bool del = false; string name; };
    Node* root = new Node();
    unordered_map<string, vector<Node*>> subTrees;
    string serialize(Node* n) {
        if(n->c.empty()) return "";
        string s = "(";
        for(auto& p: n->c) s += p.first + serialize(p.second);
        s += ")";
        subTrees[s].push_back(n);
        return s;
    }
    void dfs(Node* n, vector<string>& path, vector<vector<string>>& res) {
        if(n->del) return;
        if(n != root) res.push_back(path);
        for(auto& p: n->c) {
            path.push_back(p.first);
            dfs(p.second, path, res);
            path.pop_back();
        }
    }
public:
    vector<vector<string>> deleteDuplicateFolder(vector<vector<string>>& paths) {
        for(auto& p: paths) {
            Node* n = root;
            for(auto& f: p) {
                if(!n->c.count(f)) n->c[f] = new Node();
                n = n->c[f]; n->name = f;
            }
        }
        serialize(root);
        for(auto& p: subTrees) if(p.second.size() > 1) for(Node* n: p.second) n->del = true;
        vector<vector<string>> res; vector<string> path;
        dfs(root, path, res);
        return res;
    }
};

