class Solution {
    class Node { Map<String, Node> c = new TreeMap<>(); boolean del = false; String name; }
    Node root = new Node();
    Map<String, List<Node>> subTrees = new HashMap<>();
    String serialize(Node n) {
        if(n.c.isEmpty()) return "";
        StringBuilder sb = new StringBuilder("(");
        for(String key: n.c.keySet()) sb.append(key).append(serialize(n.c.get(key)));
        sb.append(")");
        String s = sb.toString();
        subTrees.computeIfAbsent(s, k -> new ArrayList<>()).add(n);
        return s;
    }
    void dfs(Node n, List<String> path, List<List<String>> res) {
        if(n.del) return;
        if(n != root) res.add(new ArrayList<>(path));
        for(String key: n.c.keySet()) {
            path.add(key);
            dfs(n.c.get(key), path, res);
            path.remove(path.size()-1);
        }
    }
    public List<List<String>> deleteDuplicateFolder(List<List<String>> paths) {
        for(List<String> p: paths) {
            Node n = root;
            for(String f: p) {
                if(!n.c.containsKey(f)) n.c.put(f, new Node());
                n = n.c.get(f); n.name = f;
            }
        }
        serialize(root);
        for(List<Node> list: subTrees.values()) if(list.size() > 1) for(Node n: list) n.del = true;
        List<List<String>> res = new ArrayList<>();
        dfs(root, new ArrayList<>(), res);
        return res;
    }
}

