class Solution:
    def deleteDuplicateFolder(self, paths: List[List[str]]) -> List[List[str]]:
        class Node:
            def __init__(self): self.c = collections.defaultdict(Node); self.del_ = False
        root = Node()
        for p in paths:
            n = root
            for f in p: n = n.c[f]
        subTrees = collections.defaultdict(list)
        def serialize(n):
            if not n.c: return ""
            s = "(" + "".join(k + serialize(n.c[k]) for k in sorted(n.c)) + ")"
            subTrees[s].append(n)
            return s
        serialize(root)
        for s, nodes in subTrees.items():
            if len(nodes) > 1:
                for n in nodes: n.del_ = True
        res = []
        def dfs(n, path):
            if n.del_: return
            if path: res.append(list(path))
            for k in sorted(n.c):
                path.append(k)
                dfs(n.c[k], path)
                path.pop()
        dfs(root, [])
        return res

