        self.enc = dict(zip(keys, values))
        self.dec = collections.Counter()
        for w in dictionary:
            e = self.encrypt(w)
            if e: self.dec[e] += 1
    def encrypt(self, word1: str) -> str:
        res = []
        for c in word1:
            if c not in self.enc: return ""
            res.append(self.enc[c])
        return "".join(res)
    def decrypt(self, word2: str) -> int:
        return self.dec[word2]

