        Set<String> set = new HashSet<>();
        for(String w: dict) {
            StringBuilder sb = new StringBuilder(w);
            for(int i=0; i<w.length(); i++) {
                char temp = sb.charAt(i);
                sb.setCharAt(i, '*');
                String s = sb.toString();
                if(set.contains(s)) return true;
                set.add(s);
                sb.setCharAt(i, temp);
            }
        }
        return false;
